var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저게 그 방주인가?","JPN":"あれが、例の箱舟？","ENG":"So is that the Ark?","TWN":"那就是方舟？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그래. 너도 그때 같이 있지 않았나.","JPN":"ああ。あの時はお前も一緒だっただろう？","ENG":"Yes. You were there too, weren't you?","TWN":"對，妳當時不是也在現場嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"난 부상 때문에 주위를 살필 여유가 없었어.","JPN":"私は重症だったから周りに気を配る余裕がなかったわ。","ENG":"I was too wounded to really take a look at what was going on around me.","TWN":"我那時因為受傷，沒有空去觀察周圍。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만...... 기억에 있는 것과 비슷하긴 하네.","JPN":"でも……確かに記憶の奥深くの景色と似ているわ。","ENG":"However... I do seem to remember something like that.","TWN":"不過……跟記憶中的樣子很像。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그럼 괜히 지체할 필요도 없겠군. 곧장 함선으로 진입한다.","JPN":"なら戸惑っている理由はないな。ただちに艦船へ進入しよう。","ENG":"Then there's no need to delay this any further. We'll breach the ship immediately.","TWN":"那就不要多作猶豫了，直接進入艦船吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음......","JPN":"うむ……","ENG":"Hmm...","TWN":"來吧……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"방주 앞에 누군가 있군. 아는 얼굴인가?","JPN":"箱舟の前に誰かいるな。君の知り合いか？","ENG":"There's someone in front of the Ark. An old friend of yours?","TWN":"方舟前面有人，那些人妳認識嗎？"},"stage":{"bg":"MAINSTREAM_124010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"저 녀석은......","JPN":"あいつは……","ENG":"That's...","TWN":"那些傢伙是……"},"stage":{"bg":"MAINSTREAM_124010","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"어라? 류드밀라?","JPN":"あら～！　リュドミラちゃん？","ENG":"Huh? Lyudmila?","TWN":"咦？ 盧德米拉？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"목숨만 건져서 도망가더니 다시 죽으러 왔어?","JPN":"せっかく命からがら逃げ出せたのに、また殺されに来たの？","ENG":"You barely made it out alive before. Are you here to let us finish the job?","TWN":"妳明明冒著生命危險逃跑，結果還要回來送死嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"이해가 안 되네. 혹시 사는 게 지겨워?","JPN":"理解不能だわ。もしかして生きてるのが面倒になっちゃった？","ENG":"I don't understand. Are you that tired of living already?","TWN":"真是無法理解，妳是活膩了嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"아니면...... 남아 있는 동료들을 구하겠다거나 하는 시시한 이유 때문이려나?","JPN":"それとも……残された仲間たちを救うだとか、\\nそんなチャチな理由なのかしら？","ENG":"Or... are you here for some lame reason, like saving your troops?","TWN":"還是……妳是為了來救留下來的同伴，為了這樣愚蠢的理由？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"닥쳐라, 더러운 그림자 놈!","JPN":"黙れ、汚らわしいシャドウめ！","ENG":"Shut your dirty Shadow mouth!","TWN":"閉嘴，骯髒的暗影！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이번에야말로 도륙을 내 주지!","JPN":"今度こそ八つ裂きにしてくれる！","ENG":"I will cut you to pieces this time!","TWN":"我這次一定要宰了妳！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"아, 그래? 꿈이 참 야무지네.","JPN":"あっ、そぉ？　残念だけどそれは無理よ。","ENG":"Oh, is that so? Dream on, girl.","TWN":"喔，是嗎？妳還真是會作夢呢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"예고르, 발레리. 환영식을 열어 줘.","JPN":"イェゴールちゃん、ヴァレリーちゃん。盛大に歓迎してあげて。","ENG":"Yegor, Valeriy. Throw our old friend a welcome party.","TWN":"伊高爾，瓦萊里，為她開個歡迎派對吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......함정이군요. 포위당했습니다.","JPN":"……ハメられましたね。囲まれています。","ENG":"It's a trap. We've been surrounded.","TWN":"……是陷阱，我們被包圍了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"시끌벅적하게 소란을 피우면서 오는데 아무 준비 없이 기다릴 리가 없잖아.","JPN":"あんな賑やかに騒ぎながら来てたのに、\\n何の準備もなしに迎えるわけないじゃない。","ENG":"Well, we had no reason to stay unprepared with all the noise you guys were making on the way here.","TWN":"你們一路上吵吵鬧鬧地過來，我不可能沒做些準備吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"잘됐어. 안 그래도 동결을 해제할 방법이 없어서 짜증나던 참인데.","JPN":"ちょうど良かったわ。\\n凍結を解除する手立てがなくてイラッと来てたところなの。","ENG":"This is great. I was getting annoyed that we didn't have a way to release the stasis.","TWN":"剛好，我因為無法解除凍結，正煩得要命呢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"심심풀이 삼아 널 잡아서 가지고 놀면 지루하진 않을 것 같아.","JPN":"あなたを転がして遊べば、退屈はしなくて済みそうね。","ENG":"I think you'll keep me entertained for the time being.","TWN":"就當作是打發時間，抓你們來玩的話，應該不會那麼無聊了吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"기대해. 아주 아주 오랫동안 귀여워해 줄게.","JPN":"期待していいわよ。たっぷり時間をかけて可愛がってあげるから。","ENG":"Don't worry. I'll keep you around for a long, long time. Wouldn't want the fun to be over too quickly.","TWN":"我很期待。我會用非常，非常長的時間，好好疼愛你們的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"곤란한 상황이군. 이래서야 우리가 먼저 당하겠어.","JPN":"困ったことになったな。このままだと我々の方がやられそうだ。","ENG":"This isn't good. They're going to get to us first at this rate.","TWN":"情況不妙，這樣我們會先遭受到攻擊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"걱정하지 마라. 놈들은 내가 상대하겠다.","JPN":"案ずるな。奴らの相手は私が引き受ける。","ENG":"Don't worry. I'll handle them.","TWN":"別擔心，交給我來對付他們。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"혼자서 말인가?","JPN":"一人でか？","ENG":"By yourself?","TWN":"妳一個人？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"전투가 내 전문은 아니지만, 저 친구들 상당한 고위급 침식체로 보이는데.","JPN":"私は戦闘のプロではないので迂闊なことは言えんが、\\n彼らはかなり高位の侵食体に見えるぞ。","ENG":"Combat may not be my field of expertise, but I can tell they're pretty high tier C.O.s.","TWN":"雖然戰鬥不是我的專長，但那些傢伙看起來都是高等侵蝕體啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"네 말대로, 전투는 내 전문 분야다.","JPN":"戦闘のプロならここに一人いる。","ENG":"Combat is my field of expertise.","TWN":"如你所說，戰鬥是我的專長。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그리고 놈들의 목표는 나 하나지. 시간은 필요한 만큼 끌어 주겠다.","JPN":"そして、奴らの狙いは私一人。必要な分の時間は稼いでやる。","ENG":"And I'm the only one they're after. I'll buy you all the time you need.","TWN":"而且它們的目標只有我，我會儘量拖時間的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그동안 너희는 함선의 동결을 해제하도록!","JPN":"貴様はその間に艦船の凍結を解除しておくように！","ENG":"In the meantime, get that stasis off the ship!","TWN":"你就趁這段時間去解除艦船的凍結！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};